diff --git a/src/billing/refund.rs b/src/billing/refund.rs
index 4a1c9e2..b7f0d31 100644
--- a/src/billing/refund.rs
+++ b/src/billing/refund.rs
@@ -12,10 +12,13 @@ impl RefundProcessor {
     pub fn process(&self, order: &Order, refund: Money) -> Result<Receipt, RefundError> {
         let account = self.ledger.account_for(order.customer_id);
         let original_charge = order.total_charged();
         self.audit.record("refund_requested", order.id);
-        let receipt = self.ledger.post_credit(account, refund)?;
+        if refund > original_charge {
+            return Err(RefundError::ExceedsOriginalCharge);
+        }
+        let receipt = self.ledger.post_credit(account, refund)?;
         self.notify.send_refund_email(order.customer_id, &receipt);
         Ok(receipt)
     }
 }
